1	export type Cell = [number, number];
2	
3	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
4	const cellOf = (key: string): Cell => {
5	  const [x, y] = key.split(",");
6	  return [Number(x), Number(y)];
7	};
8	
9	const neighborOffsets: Cell[] = [
10	  [-1, -1], [-1, 0], [-1, 1],
11	  [ 0, -1],          [ 0, 1],
12	  [ 1, -1], [ 1, 0], [ 1, 1],
13	];
14	
15	const neighborsOf = ([x, y]: Cell): Cell[] =>
16	  neighborOffsets.map(([dx, dy]) => [x + dx, y + dy]);
17	
18	export function nextGeneration(cells: Cell[]): Cell[] {
19	  const live = new Set(cells.map(keyOf));
20	
21	  const neighborCounts = new Map<string, number>();
22	  for (const cell of cells) {
23	    for (const neighbor of neighborsOf(cell)) {
24	      const k = keyOf(neighbor);
25	      neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
26	    }
27	  }
28	
29	  // Conway's rule, simplified: a cell lives next gen if it has exactly 3
30	  // neighbors, or if it is already alive with exactly 2 neighbors.
31	  const survives = (k: string, count: number): boolean =>
32	    count === 3 || (count === 2 && live.has(k));
33	
34	  return Array.from(neighborCounts)
35	    .filter(([k, count]) => survives(k, count))
36	    .map(([k]) => cellOf(k));
37	}
38

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (still life) unchanged", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.slice().sort()).toEqual(expected.slice().sort());
24	  });
25	  it("should birth a new cell when a dead cell has exactly 3 live neighbors", () => {
26	    // L-shape: ##  -> after one gen, dead cell (1,0) has 3 neighbors and is born
27	    //          #.
28	    const lShape: [number, number][] = [[0, 1], [1, 1], [0, 0]];
29	    const result = nextGeneration(lShape);
30	    expect(result).toContainEqual([1, 0]);
31	  });
32	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
33	    // Center cell (1,1) plus 4 diagonals = 4 neighbors → dies
34	    const pattern: [number, number][] = [
35	      [0, 0], [2, 0],
36	      [1, 1],
37	      [0, 2], [2, 2],
38	    ];
39	    const result = nextGeneration(pattern);
40	    expect(result).not.toContainEqual([1, 1]);
41	  });
42	  it.todo("should handle negative coordinates");
43	});
